parameters.jsCode:
// Group trip items by trip_id and analyze what's missing or not booked
const tripItems = $input.all();
const trips = $('Get Future Trips').all();
const requiredTypes = $('Set Workflow Variables').first().json.required_trip_types;

const results = [];

// Create a map of trips for easy lookup - use Map for better type safety
const tripMap = new Map();
trips.forEach(trip => {
  tripMap.set(String(trip.json.id), trip.json);
});

// Group items by trip_id - use Map for better type safety
const itemsByTrip = new Map();
tripItems.forEach(item => {
  const tripId = String(item.json.trip_id);
  if (!itemsByTrip.has(tripId)) {
    itemsByTrip.set(tripId, []);
  }
  itemsByTrip.get(tripId).push(item.json);
});

// Debug: Log what we have
console.log('Trip Map keys:', Array.from(tripMap.keys()));
console.log('Items by trip keys:', Array.from(itemsByTrip.keys()));

// Check each trip for missing or unbooked items
for (const [tripId, trip] of tripMap) {
  const items = itemsByTrip.get(tripId) || [];

  // Check if trip needs reminders (30 days or 15 days before)
  const startDate = new Date(trip.start_date);
  const now = new Date();
  const daysUntilTrip = Math.ceil((startDate - now) / (1000 * 60 * 60 * 24));

  console.log(`Trip ${tripId}: ${daysUntilTrip} days until trip`);

  const needs30DayReminder = daysUntilTrip <= 30 && daysUntilTrip > 15;
  const needs15DayReminder = daysUntilTrip <= 15 && daysUntilTrip > 0;

  if (needs30DayReminder || needs15DayReminder) {
    const existingTypes = items.map(item => item.type).filter(type => type);
    const bookedTypes = items.filter(item => item.status === 'booked').map(item => item.type);

    const issues = [];

    // Check for missing types
    requiredTypes.forEach(type => {
      if (!existingTypes.includes(type)) {
        issues.push({
          type: 'missing',
          category: type,
          message: `${type.replace('_', ' ')} not planned`
        });
      } else if (!bookedTypes.includes(type)) {
        issues.push({
          type: 'not_booked',
          category: type,
          message: `${type.replace('_', ' ')} not booked`
        });
      }
    });

    if (issues.length > 0) {
      results.push({
        user_id: trip.user_id,
        trip_id: tripId,
        trip_name: `Trip to ${trip.destination}`,
        start_date: trip.start_date,
        days_until_trip: daysUntilTrip,
        reminder_type: needs15DayReminder ? '15_day' : '30_day',
        issues: issues
      });
    }
  }
}

return results;

// Filter out trips that already have reminders sent
const tripsNeedingReminders = $('Analyze Trip Requirements').all();
const existingReminders = $input.all();

const results = [];

tripsNeedingReminders.forEach(trip => {
  const tripData = trip.json;

  // Check if this trip already has this reminder type sent
  const reminderExists = existingReminders.some(reminder => 
    reminder.json.trip_id === tripData.trip_id && 
    reminder.json.reminder_type === tripData.reminder_type &&
    reminder.json.reminder_sent === true
  );

  if (!reminderExists) {
    results.push(tripData);
  }
});

return results;

// Group trip items by trip_id and analyze what's missing or not booked
const tripItems = $input.all();
const trips = $('Get Future Trips').all();
const requiredTypes = ['flight', 'car', 'hotel', 'travel_insurance'];

const results = [];

// Create a map of trips for easy lookup
const tripMap = {};
trips.forEach(trip => {
  tripMap[trip.json.id] = trip.json;
});

// Group items by trip_id
const itemsByTrip = {};
tripItems.forEach(item => {
  const tripId = item.json.trip_id;
  if (!itemsByTrip[tripId]) {
    itemsByTrip[tripId] = [];
  }
  itemsByTrip[tripId].push(item.json);
});

// Check each trip for missing or unbooked items
for (const tripId in tripMap) {
  const trip = tripMap[tripId];
  const items = itemsByTrip[tripId] || [];

  // Check if trip needs reminders (30 days or 15 days before)
  const startDate = new Date(trip.start_date);
  const now = new Date();
  const daysUntilTrip = Math.ceil((startDate - now) / (1000 * 60 * 60 * 24));

  const needs30DayReminder = daysUntilTrip <= 30 && daysUntilTrip > 15;
  const needs15DayReminder = daysUntilTrip <= 15 && daysUntilTrip > 0;

  if (needs30DayReminder || needs15DayReminder) {
    const existingTypes = items.map(item => item.type).filter(type => type);
    const bookedTypes = items.filter(item => item.status === 'booked').map(item => item.type);

    const issues = [];

    // Check for missing types
    requiredTypes.forEach(type => {
      if (!existingTypes.includes(type)) {
        issues.push({
          type: 'missing',
          category: type,
          message: `${type.replace('_', ' ')} not planned`
        });
      } else if (!bookedTypes.includes(type)) {
        issues.push({
          type: 'not_booked',
          category: type,
          message: `${type.replace('_', ' ')} not booked`
        });
      }
    });

    if (issues.length > 0) {
      results.push({
        trip_id: tripId,
        trip_name: trip.name || `Trip ${tripId}`,
        start_date: trip.start_date,
        days_until_trip: daysUntilTrip,
        reminder_type: needs15DayReminder ? '15_day' : '30_day',
        issues: issues
      });
    }
  }
}

return results;

